#!/bin/bash
whois $1 | awk -F':[ \t]*' 'BEGIN{g[1]="Registrant"; g[2]="Admin"; g[3]="Tech"; f[1]="Name"; f[2]="Organization"; f[3]="Street"; f[4]="City"; f[5]="State/Province"; f[6]="Postal Code"; f[7]="Country"; f[8]="Phone"; f[9]="Phone Ext"; f[10]="Fax"; f[11]="Fax Ext"; f[12]="Email"} {gsub(/^[ \t]+|[ \t]+$/, "", $1); gsub(/^[ \t]+|[ \t]+$/, "", $2); out[$1]=$2} END{for(i=1;i<=3;i++){for(j=1;j<=12;j++){k=g[i]" "f[j]; v=out[k]; if(f[j]=="Street" && v!="") v=v" "; sep=(i==3 && j==12)?"":"\n"; if(f[j] ~ /Ext/) printf("%s %s:,%s%s", g[i], f[j], v, sep); else printf("%s %s,%s%s", g[i], f[j], v, sep)}}}' > $1.csv
